targets.expr:
sum by(node)(
  label_replace(rate(container_cpu_usage_seconds_total{container!="", image!="", instance=~"$nodes", namespace=~"$namespace"}[5m]), "node", "$1", "instance", "(.*)")
)
/
sum by(node)(
  kube_node_status_allocatable{resource="cpu", node=~"$nodes"}
)

sum(
  kube_pod_container_resource_requests{resource="cpu", namespace!="", node=~"$nodes", namespace=~"$namespace"}
)
/
sum(
  kube_node_status_allocatable{resource="cpu", node=~"$nodes"}
)

(
  kube_pod_container_status_waiting_reason{
    namespace=~"$namespace",
    reason!~"ContainerCreating"
  }
  or
  kube_pod_container_status_terminated_reason{
    namespace=~"$namespace",
    reason!="Completed"
  }
)
* on (namespace, pod)
group_left(node)
kube_pod_info{node=~"$nodes"}

sum by (instance) (
  container_memory_working_set_bytes{
    container!="",
    image!="",
    pod!="",
    namespace=~"$namespace",
    instance=~"$nodes"
  }
)

sum(
  kube_pod_container_resource_requests{resource="memory", namespace!="", node=~"$nodes", namespace=~"$namespace"}
)
/
sum(
  kube_node_status_allocatable{resource="memory", node=~"$nodes"}
)

topk(
  10,
  100 *
  sum by (namespace, pod) (
    container_memory_working_set_bytes{container!="", image!="", namespace=~"$namespace", instance=~"$nodes"}
  )
  /
  sum by (namespace, pod) (
    kube_pod_container_resource_limits{resource="memory"}
  )
)
